import React, { useState, useRef, useEffect } from 'react';
import { Monitor, ArrowRight, Zap, CheckCircle2, MousePointer2, ExternalLink } from 'lucide-react';
import { ASSETS } from '../data/assets';

/**
 * WEB SHOWCASE V2 - "MacBook Hover Scroll"
 * 
 * Concept: Instead of a modal, we present a CSS-styled MacBook.
 * Interaction: Moving the mouse vertically over the screen scrolls the 
 * full-page screenshot relative to the cursor position.
 */

const WebShowcase: React.FC = () => {
  const [activeProject, setActiveProject] = useState(ASSETS.webProjects[0]);
  const [scrollPos, setScrollPos] = useState(0);
  const screenRef = useRef<HTMLDivElement>(null);
  const [isHovering, setIsHovering] = useState(false);

  // Handle the "Hover Scroll" logic
  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!screenRef.current) return;

    const { top, height } = screenRef.current.getBoundingClientRect();
    const y = e.clientY - top; // Mouse Y relative to container

    // Calculate percentage (0 to 1)
    let percentage = y / height;

    // Clamp percentage
    if (percentage < 0) percentage = 0;
    if (percentage > 1) percentage = 1;

    setScrollPos(percentage);
  };

  return (
    <section id="web-showcase" className="py-24 bg-movie-black border-t border-white/5 relative overflow-hidden">
      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-blue-900/20 via-movie-black to-movie-black pointer-events-none"></div>

      <div className="container mx-auto px-6 relative z-10">

        {/* Header */}
        <div className="text-center mb-16">
          <div className="inline-flex items-center gap-2 px-4 py-2 bg-blue-900/10 border border-blue-500/30 rounded-full mb-4">
             <Monitor size={16} className="text-blue-400 animate-pulse" />
             <span className="text-blue-400 text-xs font-bold uppercase tracking-widest">Web Experience</span>
          </div>
          <h2 className="text-4xl md:text-6xl font-heading font-black text-white mb-4">
             ARQUITECTURA <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-cyan-400">DIGITAL</span>
          </h2>
          <p className="text-movie-silver max-w-xl mx-auto">
             Explora nuestros desarrollos. Pasa el cursor sobre la pantalla para navegar por la interfaz en tiempo real.
          </p>
        </div>

        <div className="flex flex-col lg:flex-row gap-12 items-center max-w-7xl mx-auto">

           {/* 1. LEFT: PROJECT SELECTOR & STATS */}
           <div className="w-full lg:w-1/3 space-y-2">
              <p className="text-xs font-bold text-movie-silver uppercase tracking-widest mb-4 ml-2">Selecciona un Proyecto:</p>

              {ASSETS.webProjects.map((project) => (
                 <button
                    key={project.id}
                    onClick={() => { setActiveProject(project); setScrollPos(0); }}
                    className={`w-full text-left p-6 rounded-xl border transition-all duration-300 group relative overflow-hidden ${
                       activeProject.id === project.id 
                       ? 'bg-white/5 border-blue-500 shadow-[0_0_30px_rgba(59,130,246,0.1)]' 
                       : 'bg-transparent border-white/5 hover:bg-white/5 hover:border-white/20'
                    }`}
                 >
                    <div className="relative z-10 flex justify-between items-center">
                       <div>
                          <h4 className={`text-lg font-bold transition-colors ${activeProject.id === project.id ? 'text-white' : 'text-movie-silver group-hover:text-white'}`}>
                             {project.title}
                          </h4>
                          <p className="text-xs text-blue-400 font-mono mt-1">{project.category}</p>
                       </div>
                       {activeProject.id === project.id && <Zap className="text-blue-500" size={18} />}
                    </div>

                    {/* Progress Bar Background for active item */}
                    {activeProject.id === project.id && (
                       <div className="absolute bottom-0 left-0 h-1 bg-blue-500 animate-[width_0.5s_ease-out] w-full"></div>
                    )}
                 </button>
              ))}

              {/* Project Details Box */}
              <div className="mt-8 p-6 bg-blue-900/10 border border-blue-500/20 rounded-xl animate-fade-in-up">
                 <h5 className="text-white font-bold mb-3 flex items-center gap-2">
                    <CheckCircle2 size={16} className="text-blue-400"/> Stack Tecnológico
                 </h5>
                 <p className="text-sm text-movie-silver leading-relaxed mb-4">
                    {activeProject.description}
                 </p>
                 <div className="flex items-center justify-between pt-4 border-t border-white/10">
                    <span className="text-xs text-blue-300 font-mono">Velocidad: 98/100</span>
                    <a 
                       href={`https://${activeProject.url}`} 
                       target="_blank" 
                       rel="noopener noreferrer"
                       className="text-xs font-bold text-white hover:text-blue-400 flex items-center gap-1 uppercase"
                    >
                       Visitar sitio <ExternalLink size={12}/>
                    </a>
                 </div>
              </div>
           </div>

           {/* 2. RIGHT: MACBOOK HOVER SCROLL */}
           <div className="w-full lg:w-2/3 perspective-1000">

              {/* CSS MacBook Chassis */}
              <div className="relative mx-auto bg-[#1a1a1a] rounded-[1.5rem] border-[1px] border-[#333] shadow-2xl w-full max-w-3xl aspect-[16/10] p-1.5 md:p-3 transform transition-transform duration-700 hover:rotate-x-2">

                 {/* Lid Border */}
                 <div className="absolute inset-0 rounded-[1.2rem] border-[2px] border-[#000] pointer-events-none z-20"></div>

                 {/* Screen Container */}
                 <div 
                    ref={screenRef}
                    onMouseEnter={() => setIsHovering(true)}
                    onMouseLeave={() => setIsHovering(false)}
                    onMouseMove={handleMouseMove}
                    className="relative w-full h-full bg-black rounded-[1rem] overflow-hidden cursor-none group"
                 >
                    {/* The Full Page Image */}
                    <img 
                       src={activeProject.desktopImg} 
                       alt={activeProject.title}
                       className="w-full absolute top-0 left-0 transition-transform duration-100 ease-linear will-change-transform"
                       style={{ 
                          // The magic formula: Translate Y based on cursor % * (Image Height - Container Height)
                          transform: `translateY(-${scrollPos * (100 - (screenRef.current ? (screenRef.current.offsetHeight / screenRef.current.scrollHeight) * 100 : 20))}%)` 
                       }}
                       onLoad={(e) => {
                          // Allow image to render naturally to calculate scroll height visually
                          const img = e.currentTarget;
                          img.style.height = 'auto'; 
                       }}
                    />

                    {/* Custom Cursor Overlay */}
                    <div 
                       className={`absolute inset-0 pointer-events-none flex items-center justify-center bg-black/60 backdrop-blur-[2px] transition-opacity duration-500 z-30 ${isHovering ? 'opacity-0' : 'opacity-100'}`}
                    >
                       <div className="flex flex-col items-center animate-bounce">
                          <MousePointer2 size={32} className="text-white fill-white mb-2" />
                          <span className="text-xs font-bold text-white uppercase tracking-widest bg-black/50 px-3 py-1 rounded-full border border-white/20">
                             Pasa el mouse para navegar
                          </span>
                       </div>
                    </div>

                    {/* Interaction Hint (follows mouse technically via CSS cursor, but here static overlay) */}
                    <div className={`absolute top-4 right-4 z-20 transition-opacity duration-300 ${isHovering ? 'opacity-100' : 'opacity-0'}`}>
                       <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_#22c55e]"></div>
                    </div>
                 </div>

                 {/* Reflection/Gloss */}
                 <div className="absolute inset-0 bg-gradient-to-tr from-white/5 to-transparent rounded-[1.5rem] pointer-events-none z-40"></div>

              </div>

              {/* MacBook Base (Visual only) */}
              <div className="relative mx-auto w-[110%] -ml-[5%] h-4 bg-[#222] rounded-b-xl mt-[-2px] shadow-xl border-t border-[#333] flex justify-center">
                 <div className="w-1/3 h-2 bg-[#111] rounded-b-lg"></div>
